INSERT INTO public.photos VALUES (23478, 'Pl. de San Carlos 1890', 'Imagen centrada en la fachada de la antigua casa denominada de los Morlanes en la plaza de San Carlos. Al fondo, en la esquina de la calle de San Jorge con la de la Zarza, el antiguo colegio de "La Enseâ”œâ–’anza" de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. Fuente visual: fototipia de Joarizti y Mariezcurrena, en أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65158500, -0.87585800, '0101000020E610000038143E5B0707ECBF36C8242367D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34508717891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34508717891.webp', 'https://www.flickr.com/photos/zaragozaantigua/34508717891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23495, 'Plaza de San Carlos c.1877', 'Imagen de la antigua casa del siglo XVI conocida como de los Morlanes sita en la plaza de San Carlos que, en el momento de esta captura visual acogâ”œآ،a entre otros establecimientos a la Fâ”œأ­brica de pianos de Arilla, Menchaca y Compaâ”œâ–’â”œآ،a. En la penumbra del interior, traspasada la puerta, destaca el carro de los abundantes materiales, productos y utensilios fotogrâ”œأ­ficos de la sociedad J. Laurent y Cia., responsable de la factura de esta fotografâ”œآ،a. En primer tâ”œآ®rmino y a la izquierda, vista parcial del pilar izquierdo sobre el que se eleva la portada de ingreso a la iglesia de la Inmaculada Concepciâ”œâ”‚n de Marâ”œآ،a del Real Seminario de San Carlos Borromeo.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.65169500, -0.87571900, '0101000020E6100000DF8B2FDAE305ECBFBDFBE3BD6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54225419607.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54225419607.webp', 'https://www.flickr.com/photos/zaragozaantigua/54225419607/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23543, 'La Enseâ”œâ–’anza c.1927', 'AHPZ. Josâ”œآ® Galiay Saraâ”œâ–’ana. Imagen del Convento de La Enseâ”œâ–’anza, en su antigua ubicaciâ”œâ”‚n de la calle de San Jorge, tomada desde la calle del Câ”œآ،ngulo. En el siglo XVII fue creada La Compaâ”œâ–’â”œآ،a de Marâ”œآ،a N. S., primer instituto religioso de carâ”œأ­cter educativo para la mujer, denominado "La Enseâ”œâ–’anza". En 1712, por orden de Felipe V, se fundâ”œâ”‚ en Zaragoza el أ”أ‡آ£Real Refugio de Niâ”œâ–’as Huâ”œآ®rfanasأ”أ‡أک. De 1740 es la construcciâ”œâ”‚n de la iglesia sita en la calle de San Jorge, gemela de la de la Santa Cruz. Su autor fue Ventura Rodrâ”œآ،guez. En 1744 se funda el convento de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. En marzo de 1928 el colegio se traslada a unas nuevas instalaciones en la calle Bilbao. El antiguo edificio de la calle San Jorge fue demolido inmediatamente, y reurbanizada toda la manzana. La apertura de la nueva calle de San Vicente de Paâ”œâ•‘l en los aâ”œâ–’os 40 del siglo XX le conferirâ”œأ­ su ordenaciâ”œâ”‚n actual.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15326232965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15326232965.webp', 'https://www.flickr.com/photos/zaragozaantigua/15326232965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23552, 'Calle San Jorge aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, mostrando la antigua calle de la Enseâ”œâ–’anza, luego de San Jorge, con el Convento de La Enseâ”œâ–’anza a la izquierda, que fue demolido en los aâ”œâ–’os 30. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19865349275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19865349275.webp', 'https://www.flickr.com/photos/zaragozaantigua/19865349275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23555, 'Coso Bajo 14 de abril 1931', 'Imagen de la "inmensa riada humana, sobre la que flotan al viento las banderas de la Repâ”œâ•‘blica y se alzan los retratos de Galâ”œأ­n y de Garcâ”œآ،a Hernâ”œأ­ndez", encauzada por el Coso. El colectivo posado ha sido realizado un luminoso dâ”œآ،a de abril de 1931 en la confluencia de las antiguas "Piedras del Coso" (inmediatas a la izquierda), el arranque del Coso Bajo hacia la Magdalena (al frente), y la entrada a la plaza de San Miguel por la calle de Baldomero Espartero (a la derecha).', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65078100, -0.87620200, '0101000020E6100000C712D6C6D809ECBFD9EDB3CA4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21701272528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21701272528.webp', 'https://www.flickr.com/photos/zaragozaantigua/21701272528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23556, 'Piedras del Coso 1931', 'Imagen de uno de los escenarios conflictuales durante la dura e intensa Huelga de Telefâ”œâ”‚nica desarrollada entre finales de agosto y primeros dâ”œآ،as de setiembre de ese aâ”œâ–’o. La captura se ha realizado en el punto de enlace del Coso Medio (al fondo), la calle de Espartero, y el arranque del tramo Bajo (hacia la derecha), antiguamente denominado "Las piedras del Coso" hasta la plaza de la Magdalena. Esto era asâ”œآ، porque durante mucho tiempo la romana muralla que cercaba la ciudad fue empleada, en este lugar, como cantera de precisos sillares que fueron reciclados en numerosas construcciones posteriores. Cuando a principios del siglo XIX se construyeron las casas de la esquina, en su fachada fue colocada una placa ideada por Miguel de Villalba y Aybar, a la sazâ”œâ”‚n Regente de la Real Audiencia de Aragâ”œâ”‚n, con un exâ”œأ­metro latino que informaba "Saxevs Hac Mvrvs Veterisqve Hic Terminvs Vrbis" ("Este es el antiguo muro de piedra que daba tâ”œآ®rmino a la ciudad"). Esta es la placa que aparece en la imagen, en sol y sombra, por la casual incidencia cenital del sol en ese momento. Mal que bien, edificio y placa llegaron al siglo XXI en su sitio, pero en un momento determinado, la placa fue arrancada justo antes del derribo del inmueble. Luego, el edificio fue demolido. La placa, en paradero desconocido. Tal vez donde la puerta del Duque. Fuente visual: foto Palacios, "Ahora. Diario grâ”œأ­fico" (Madrid)', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22624917319.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22624917319.webp', 'https://www.flickr.com/photos/zaragozaantigua/22624917319/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23559, 'Calle del Gallo 1967', 'Calle del Gallo, sin salida, y con entrada desde la calle de los Estudios. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65182200, -0.87492600, '0101000020E61000006D718DCF64FFEBBF1B683EE76ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22753528639.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22753528639.webp', 'https://www.flickr.com/photos/zaragozaantigua/22753528639/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26035, 'Azud del Ebro 2006', 'Foto: Esther Casas. Obras de cimentaciâ”œâ”‚n del futuro azud Manuel Lorenzo Pardo sobre el râ”œآ،o Ebro, en agosto de 2006. Esta presa se inaugurâ”œâ”‚ en 2008, construida a fin de que las embarcaciones de recreo pudieran contar con una lâ”œأ­mina de agua estable. No sirviâ”œâ”‚. Tampoco se puso en marcha nunca la central hidroelâ”œآ®ctrica que habrâ”œآ،a alimentado. Ni se conoce el paso de barca alguna por las esclusas de que estâ”œأ­ provista la que, en suma, es una costosâ”œآ،sima pasarela peatonal. Algo es algo. A la derecha de la imagen, orillas del Ebro en Vadorrey. Tras el puente de la Uniâ”œâ”‚n, vista de las construcciones de la antigua ciudad. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'LAS FUENTES', 41.65285100, -0.85678700, '0101000020E61000001A6A1492CC6AEBBF98141F9F90D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31192780334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31192780334.webp', 'https://www.flickr.com/photos/zaragozaantigua/31192780334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23562, 'Calle San Jorge c.1927', 'Imagen de la calle San Jorge con visual parcial de los antiguos aleros del colegio de "La Enseâ”œâ–’anza" de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. La captura se ha realizado desde la altura del nâ”¬â•‘ 28 de esa calle, justo enfrente, un peculiar edificio que conformaba extraâ”œâ–’a esquina con la calle Câ”œآ،ngulo. A la derecha, galerâ”œآ،a de arquillos cegados y alero del gran edificio principal del colegio, entre la calle San Jorge y la de la Zarza. El alero mâ”œأ­s inmediato, e inferior de altura, formaba parte de unas dependencias que configuraban un patio interior del complejo colegial. Si alguien necesita urgentemente hacer una comparativa con el tiempo mâ”œأ­s cercano, que siempre serâ”œأ­ pasado, tendrâ”œآ،a que situarse justo en la confluencia de las actuales calles de San Vicente de Paâ”œâ•‘l, y de San Jorge, pero poco rato. â”œأ¼nimo. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65211200, -0.87607300, '0101000020E610000051137D3ECA08ECBF22AAF06778D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23097774451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23097774451.webp', 'https://www.flickr.com/photos/zaragozaantigua/23097774451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23571, 'Iglesia de San Carlos aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste mostrando la puerta de la iglesia del Seminario de San Carlos, en la plaza homâ”œâ”‚nima. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65169200, -0.87558200, '0101000020E6100000B3EBDE8AC404ECBF4C88B9A46AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629310463.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629310463.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629310463/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23577, 'Calle de San Jorge 1931', 'Imagen del antiguo Convento de la Enseâ”œâ–’anza durante su derribo. Sus primeras instalaciones fueron inauguradas como colegio en los â”œâ•‘ltimos aâ”œâ–’os del siglo XVII en la entonces calle de la Compaâ”œâ–’â”œآ،a. Desde 1712 fue Real Refugio de Niâ”œâ–’as Huâ”œآ®rfanas, y en 1744 ya funcionâ”œâ”‚ como Real Colegio de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. Tras su traslado a una nueva, mayor y mâ”œأ­s moderna ubicaciâ”œâ”‚n en la calle de Bilbao, el antiguo convento-colegio fue derribado y sobre su solar se construyâ”œâ”‚ una nueva manzana edilicia, dejando espacio para la prevista prolongaciâ”œâ”‚n de la calle de la Yedra desde el Coso hasta el paseo de la Ribera, proyecto que aâ”œâ–’os mâ”œأ­s tarde se concretarâ”œأ­ en la apertura de la nueva calle de San Vicente de Paâ”œâ•‘l. Despuâ”œآ®s del derribo del colegio, este tramo de la calle de San Jorge fue tambiâ”œآ®n ensanchado unos metros. En la imagen, a la derecha, fachada principal del antiguo colegio, en la que destaca bajo los rayos de sol el ingreso a la iglesia colegial diseâ”œâ–’ada por el arquitecto Ventura Rodrâ”œآ،guez Tizâ”œâ”‚n. La inmediata zona recayente a la calle de la Zarza ya ha sido derribada. Al fondo, angular zona de encuentro de la calle de San Jorge con la calle del Câ”œآ،ngulo. A la izquierda, fachada de la Casa de los Morlanes, con entrada principal desde la plaza de San Carlos. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65192900, -0.87576100, '0101000020E61000009A97C3EE3B06ECBF3128D36872D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34498969853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34498969853.webp', 'https://www.flickr.com/photos/zaragozaantigua/34498969853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23597, 'Plazuela de San Carlos 1929', 'Imagen capturada en la plazuela de San Carlos a la puerta del homâ”œâ”‚nimo Seminario Sacerdotal con un grupal posado de caballeros y damas de la nobilâ”œآ،sima Real Maestranza de Caballerâ”œآ،a de Zaragoza a la salida del oficio religioso realizado en la barroca iglesia del seminario en honor de su patrono el seâ”œâ–’or San Jorge. En el centro de la escena y en segundo plano, el destacado caballero Luis Gonzaga de Azara y Lâ”œâ”‚pez Fernâ”œأ­ndez de Heredia, marquâ”œآ®s de Nibbiano.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65143000, -0.87585900, '0101000020E61000004F081D740907ECBF0FD1E80E62D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52153195619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52153195619.webp', 'https://www.flickr.com/photos/zaragozaantigua/52153195619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23598, 'Plazuela de San Carlos c.1925', 'Inâ”œآ®dita imagen capturada desde la segunda planta de la municipal escuela "los Graneros" habilitada en el antiguo Almudâ”œآ، de la ciudad y con entrada por la calle de Santo Dominguito de Val (actual Centro Pâ”œâ•‘blico de Educaciâ”œâ”‚n para Adultos "Concepciâ”œâ”‚n Arenal"). Centra la escena la empedrada plazuela de San Carlos (antigua del Seminario), dominada por la rotunda fachada barroca del Real Seminario de San Carlos del que emerge la esbelta torre emplazada a la derecha de la puerta de ingreso a la iglesia de la Inmaculada adosada al Seminario. A la izquierda, primeros nâ”œâ•‘meros de la plazuela, donde destaca el inmueble del nâ”¬â•‘ 2, tras el cual queda el nâ”¬â•‘ 3, antigua casa de los Morlanes entonces con funciones de sucursal de la fâ”œأ­brica de aguardientes "la Industrial Licorera Espaâ”œâ–’ola S.A. Cooperativa". Al fondo y tras la calle de San Jorge, leve vista de la manzana de casas delimitada entre las calles de la Zarza, el Espino y los Estudios. Aâ”œâ–’os mâ”œأ­s tarde esa manzana serâ”œآ،a retranqueada para homologar la anchura de ese tramo de la calle de San Jorge hasta entonces bien recoleto, y lo mismo se harâ”œآ،a con sus fachadas recayentes a las calles de la Zarza y del Espino.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65146200, -0.87592300, '0101000020E6100000FE0DDAAB8F07ECBF1B4B581B63D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53231312979.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53231312979.webp', 'https://www.flickr.com/photos/zaragozaantigua/53231312979/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23607, 'Coso Medio c.1884', 'Tramo medio del Coso, entre "Las piedras del Coso" (esquina de la derecha) hasta la actual plaza de Espaâ”œâ–’a (con la fuente de la Princesa, al fondo). A la izquierda y delimitada por las calles del Agua y de Flandro, la dieciochesca casa de Juan Bautista Casabona, proyectada por el arquitecto Agustâ”œآ،n Sanz.', 1884, 1884, 1884, 'Siglo XIX', 'CENTRO', 41.65068000, -0.87657500, '0101000020E6100000E9B7AF03E70CECBFA514747B49D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974349567.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974349567.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974349567/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23615, 'Coso Medio 1902', 'Imagen del tramo medio del Coso zaragozano, entre "Las piedras del Coso" (esquina de la derecha) hasta la plaza de la Constituciâ”œâ”‚n al fondo, donde sigue Neptuno. En los laterales de la calzada, los nuevos carriles de vâ”œآ،a necesarios para el cambio a la tracciâ”œâ”‚n elâ”œآ®ctrica. A finales de aâ”œâ–’o ya estarâ”œأ­ terminada la electrificaciâ”œâ”‚n de las lâ”œآ،neas que por aquâ”œآ، pasan: la del Bajo Aragâ”œâ”‚n, y la de Circunvalaciâ”œâ”‚n. Mientras, la original tracciâ”œâ”‚n, a propulsiâ”œâ”‚n de sangre, sigue prestando servicio. A la izquierda y delimitada por las calles del Agua y de Flandro, la dieciochesca casa de Juan Bautista Casabona, proyectada por el arquitecto Agustâ”œآ،n Sanz y remodelada a finales de la dâ”œآ®cada de 1880.', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18938622113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18938622113.webp', 'https://www.flickr.com/photos/zaragozaantigua/18938622113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25124, 'Cementerio de La Cartuja 1947', 'Camposanto del hospital, acuarela sobre papel, Guillermo Pâ”œآ®rez Bailo, Diputaciâ”œâ”‚n de Zaragoza, 1947. Fuente: web.dpz.es/arscatalogi.es/', 1947, 1947, 1947, 'Anos 40', NULL, 41.62937200, -0.85387600, '0101000020E610000083DBDAC2F352EBBF5182FE428FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15876354265.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15876354265.webp', 'https://www.flickr.com/photos/zaragozaantigua/15876354265/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23620, 'Calle Flandro 1874', '"Zaragoza. Aspecto de la calle de Flandro el 4 del actual, momentos antes de la lucha". Grabado de Rico sobre dibujo de Domâ”œآ®c. Ante el golpe de Estado del general Pavâ”œآ،a del 3 de enero de 1874, los republicanos organizaron protestas en diversas localidades espaâ”œâ–’olas. En Zaragoza se construyeron barricadas y se tomaron algunas calles, como la de Mateo Flandro, entre el Coso Medio y la calle de San Miguel. La revuelta fue sofocada a bayoneta. Fuente: "La ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana", 15 de enero de 1874.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65062600, -0.87692300, '0101000020E6100000D386C3D2C00FECBFB2F677B647D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29569064422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29569064422.webp', 'https://www.flickr.com/photos/zaragozaantigua/29569064422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23621, 'Coso Medio 1937', 'Foto: Marâ”œآ،n Chivite. Febrero de 1937. Desfile de las tropas de los sublevados, procedente de la calle de Baldomero Espartero. Al fondo a la izquierda, el Coso Bajo. La columna militar se dirige por el Coso Medio hacia la plaza de Espaâ”œâ–’a. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65069800, -0.87632200, '0101000020E6100000707D586FD40AECBF4BC972124AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30920188294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30920188294.webp', 'https://www.flickr.com/photos/zaragozaantigua/30920188294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23629, 'Coso Medio 1887', 'Dibujo de la fachada principal recayente al tramo medio del Coso, en la manzana comprendida entre las calles de la Imprenta (a la izquierda) y del Agua (a la derecha), de la gran casa proyectada por el arquitecto Agustâ”œآ،n Sanz en 1768-69 para el prâ”œâ”‚cer local Juan Bautista Casabona. Poco despuâ”œآ®s de ser realizado este dibujo, la fachada fue recompuesta al gusto finisecular, permitiendo la supervivencia del inmueble hasta que en la prodigiosa dâ”œآ®cada de los aâ”œâ–’os sesenta del siglo XX, fue derribado y sobre su solar, delimitado entre las actuales calles de los Hermanos Ibarra y de Mateo Flandro, fue construido el moderno y descontextualizado edificio que desde entonces hermosea este tramo del Coso. Este es otro de los innumerables casos de pâ”œآ®rdidas patrimoniales que en la ciudad no pueden ser achacadas a los asedios franceses de 1808-1809.', 1887, 1887, 1887, 'Siglo XIX', 'CENTRO', 41.65071700, -0.87689900, '0101000020E6100000B1A4DC7D8E0FECBFC2F9D4B14AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50071296187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50071296187.webp', 'https://www.flickr.com/photos/zaragozaantigua/50071296187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24006, 'Coso Medio 1988', 'Manifestaciâ”œâ”‚n sindical unitaria el 14 de diciembre de 1988, dâ”œآ،a de huelga general en Espaâ”œâ–’a contra la polâ”œآ،tica antisocial del gobierno del PSOE. Al fondo, esquina del Coso Bajo con la calle de Baldomero Espartero (derecha). Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Aragâ”œâ”‚n", UGT, 2000.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23760225719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23760225719.webp', 'https://www.flickr.com/photos/zaragozaantigua/23760225719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24043, 'Coso Medio 1986', 'Foto: Juan Gonzâ”œأ­lez Misis. Entre junio y noviembre de 1986, los trabajadores de Transportes Urbanos de Zaragoza (TUZSA), la empresa de los autobuses urbanos, mantuvieron una huelga. En la imagen, manifestaciâ”œâ”‚n de la plantilla en huelga a su paso por el Coso Medio. Al fondo, calle de Baldomero Espartero. Fuente: Heraldo de Aragâ”œâ”‚n.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65069800, -0.87648300, '0101000020E6100000BDFF8F13260CECBF4BC972124AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30923152334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30923152334.webp', 'https://www.flickr.com/photos/zaragozaantigua/30923152334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24905, 'Coso 99, 2001', 'Tras el derribo de los inmuebles de la calle del Coso de Zaragoza a la altura del 99 y el 101, aparecieron restos de la muralla y su torreâ”œâ”‚n de â”œآ®poca romana (s. III). El chirriante edificio del nâ”œâ•‘mero 99 ocupa el solar de la foto, tomada desde su interior. En el 101, lugar conocido como "las piedras del Coso", persiste un solar con los restos, donde el Coso Medio hace esquina con el Coso Bajo. Fuente: Crâ”œâ”‚nica de Zaragoza. Ayuntamiento de Zaragoza, 2001.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18547615678.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18547615678.webp', 'https://www.flickr.com/photos/zaragozaantigua/18547615678/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25059, 'Plaza de San Pedro Nolasco c.1971', 'En la plaza de San Lorenzo, luego abierta e inclusa en la de san Pedro Nolasco, se levantaba el edificio del fondo a la derecha, colegio nuevo de los hermanos Maristas construido en 1946 y abandonado por â”œآ®stos en 1981 (con entrada principal por San Vicente de Paâ”œâ•‘l 13). A su izquierda, la fonda El Descanso y el mercado San Lorenzo. Las personas que aparecen en la foto son Feliciano Romeo, que se encargâ”œâ”‚ de los cuidados del fotâ”œâ”‚grafo Aurelio Grasa hasta su fallecimiento; Emilio Grasa, hermano menor de Aurelio y que estuvo tambiâ”œآ®n al cuidado de Feliciano en su residencia en el Seminario de San Carlos; y Teresa Grasa, pintora y restauradora, hija de Aurelio y sobrina de Emilio, al que coge del brazo. Fuente: Colecciâ”œâ”‚n Antonio Tausiet.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65279200, -0.87679200, '0101000020E6100000309FAC18AE0EECBF938B31B08ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14915071231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14915071231.webp', 'https://www.flickr.com/photos/zaragozaantigua/14915071231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25682, 'Pl. San Pedro Nolasco 1923', 'Inâ”œآ®dita imagen capturada desde la calle de San Jorge, a espaldas de la barroca iglesia de San Pedro Nolasco (desaparecida), y centrada en la homâ”œâ”‚nima plaza que hacia el fondo conduce a la calle de San Juan y San Pedro (izquierda), y a la de los Hermanos Argensola (centro). A la derecha del antiguo inmueble del nâ”¬â•‘ 2 de esa calle, acceso a las calles de San Lorenzo y del Laberinto. En el centro de esta plaza y a finales de aâ”œâ–’o se instalarâ”œآ،a el Monumento a los Hermanos Argensola, obra de Josâ”œآ® Bueno Gimeno. Esta plaza todavâ”œآ،a era conocida como de San Lorenzo, en referencia a la antigua iglesia del mismo nombre que habâ”œآ،a sido derribada en el â”œâ•‘ltimo cuarto del siglo XIX.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65276900, -0.87698500, '0101000020E610000055A4C2D84210ECBFDB6B41EF8DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51284598446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51284598446.webp', 'https://www.flickr.com/photos/zaragozaantigua/51284598446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25686, 'Iglesia de San Lorenzo 1864', 'Imagen de la desaparecida iglesia de San Lorenzo cuyo derribo en 1868 alumbrâ”œâ”‚ la apariciâ”œâ”‚n de una nueva plaza donde estaba previsto construir un mercado que sâ”œâ”‚lo estuvo listo en 1876. El aspecto que muestra la iglesia se corresponde con la traza que adquiriâ”œâ”‚ tras la gran reforma barroca de que fue objeto en el siglo XVII.', 1864, 1864, 1864, 'Siglo XIX', 'CENTRO', 41.65256900, -0.87685700, '0101000020E6100000F6984869360FECBF14B1886187D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387131345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387131345.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387131345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25903, 'Coso Medio 1902', 'Postal "Agustâ”œآ،n Alluâ”œآ®", de la Serie "Zaragoza", nâ”¬â•‘ 26 "Vista del Coso". Imagen del Coso Medio, entre las "Piedras del Coso" (inmediato edificio de la esquina derecha) y la plaza de la Constituciâ”œâ”‚n (al fondo). Las lâ”œآ،neas del tranvâ”œآ،a "Circunvalaciâ”œâ”‚n", y "Bajo Aragâ”œâ”‚n" ya estâ”œأ­n electrificadas. Fuente visual: maestrogozalbo.com/', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65080400, -0.87655700, '0101000020E6100000508E0244C10CECBF910DA48B4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20610242121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20610242121.webp', 'https://www.flickr.com/photos/zaragozaantigua/20610242121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25977, 'Iglesia del Sagrado Corazâ”œâ”‚n 1985', 'Vista de Zaragoza desde la torre de la Magdalena, dentro del programa de actividades de las fiestas del Pilar "Visita a la ciudad desconocida". Preside la imagen la iglesia del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s en la plaza de San Pedro Nolasco, construida en 1942 sobre el solar de la de San Lorenzo, derribada en 1930. Es un edificio neogâ”œâ”‚tico de Regino Borobio, utilizado hoy como almacâ”œآ®n expositivo del Rosario de Cristal, colecciâ”œâ”‚n de faroles y carrozas que desfilan en octubre por la ciudad desde 1889. Fuente: Archivo municipal del Ayuntamiento de Zaragoza, 7/10/85.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65226300, -0.87706000, '0101000020E6100000FE261422E010ECBF07B29E5A7DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15191728375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15191728375.webp', 'https://www.flickr.com/photos/zaragozaantigua/15191728375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26076, 'Barrio de la Magdalena c.1895', 'Imagen capturada desde la altura de la torrecilla de la iglesia de San Carlos Borromeo y orientada hacia el noreste urbano, que incluye los inmediatos tejados del caserâ”œآ،o del barrio de la Magdalena en las calles de la Zarza, Espino, Gallo, San Lorenzo, Mayor... Sobre ellas emerge rotunda y en primer tâ”œآ®rmino la torre de la parroquia de santa Marâ”œآ،a Magdalena, y a la izquierda y al fondo, la de san Nicolâ”œأ­s de Bari. Al otro lado del râ”œآ،o Ebro se nos muestra una interesante vista de la torre del antiguo convento de Jesâ”œâ•‘s.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65236000, -0.87488200, '0101000020E6100000857D3B8908FFEBBFFA9B508880D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52210025192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52210025192.webp', 'https://www.flickr.com/photos/zaragozaantigua/52210025192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20890, 'Caesaraugusta s. III', 'Plano de la red viaria y los espacios pâ”œâ•‘blicos de la Zaragoza romana, segâ”œâ•‘n P. Galve (Ayto. de Zaragoza). Fuente visual: "La calle Alfonso I de Zaragoza", Marâ”œآ،a Pilar Galve, Ayto. Zaragoza, 2007', 250, 200, 299, 'Siglo XIX', 'CENTRO', 41.65215200, -0.87767200, '0101000020E61000005CAD1397E315ECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16162890168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16162890168.webp', 'https://www.flickr.com/photos/zaragozaantigua/16162890168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20901, 'Calle Urrea 2010', 'Vista de la excavaciâ”œâ”‚n arqueolâ”œâ”‚gica del solar de la calle Urrea 10, una vez derribado en noviembre de 2009 el edificio que lo ocupaba. Se encontraron restos del siglo 1 despuâ”œآ®s de la Era. La cloaca romana que se muestra ya habâ”œآ،a sido documentada en los solares del Coso 86 (2005) y de la calle Urrea 3-21 (2007). Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.65083400, -0.87802800, '0101000020E6100000FC1C1F2DCE18ECBFFC8F4C874ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32215215112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32215215112.webp', 'https://www.flickr.com/photos/zaragozaantigua/32215215112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20927, 'Casa de Zaporta 1560', '"Famosa escalera del Palacio de la Infanta, que existiâ”œâ”‚ en Zaragoza. Actualmente se halla colocado en Parâ”œآ،s". Ilustraciâ”œâ”‚n de la obra "Arte y Decoraciâ”œâ”‚n En Espaâ”œâ–’a" (Volumen 2), de Vâ”œآ،ctor de Falgâ”œأ­s y J. Sacs, editada entre 1917 y 1928 (a razâ”œâ”‚n de un volumen por aâ”œâ–’o) por "Casellas Moncanut Hermanos editores", Barcelona. Este dibujo representa una recreaciâ”œâ”‚n mucho mâ”œأ­s elaborada que el apuntado a lâ”œأ­piz y plumilla por Valentâ”œآ،n Carderera en 1840, de las escaleras y câ”œâ•‘pula del antiguo Palacio de Zaporta. El apunte del soldado haciendo guardia, como parte del "atrezzo" escâ”œآ®nico. Fuente visual: Colecciâ”œâ”‚n Josâ”œآ® Luis Cintora.', 1560, 1560, 1560, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24324714884.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24324714884.webp', 'https://www.flickr.com/photos/zaragozaantigua/24324714884/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20928, 'Casa de Zaporta 1545', 'Dibujo de Valentâ”œآ،n Carderera y Solano, por â”œآ®l titulado "Casa de Zaporta (1545) Zaragoza", realizado sobre 1840, en el que representa una vista desde el ingreso a esta casa palaciega por la calle Alta de San Pedro, tras haber cruzado el umbral de su puerta, con el estallido de toda la magnificencia de su singular patio. A la derecha, las escaleras de acceso a la planta principal, en el lado oeste. Los ideales personajes de "â”œآ®poca" ambientan una recreaciâ”œâ”‚n conjuntada con el entorno. Fuente visual: ceres.mcu.es/', 1545, 1545, 1545, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24328938673.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24328938673.webp', 'https://www.flickr.com/photos/zaragozaantigua/24328938673/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20931, 'Casa de Zaporta 1560', '(Zaragoza, La Casa de la Infanta, Secciâ”œâ”‚n a travâ”œآ®s del patio y escalera). Ilustraciâ”œâ”‚n de Andrew Noble Prentice para la obra "Renaissance Architecture and Ornament in Spain. A serie of examples selected from the purest works executed between the years 1500-1560, measured and drawn, together with short descriptive text" (Arquitectura y ornamento del Renacimiento en Espaâ”œâ–’a. Una serie de ejemplos seleccionados entre las obras mâ”œأ­s puras realizadas entre los aâ”œâ–’os 1500-1560, medidos y dibujados, junto con un breve texto descriptivo). Publicada en New York (1915), por la "Architectural Book Publishing Co." de Paul Wenzel & Maurice Krakow. Esta lâ”œأ­mina reproduce, ademâ”œأ­s de una pequeâ”œâ–’a planta, una interesante secciâ”œâ”‚n del patio y la caja de las escaleras de acceso a la planta principal, incluyendo el remate mediante una octogonal câ”œâ•‘pula de media naranja sobre tambor, tallada en madera, en formas mudâ”œآ®jares. La vista serâ”œآ،a desde el ingreso al Palacio por la calle Alta de San Pedro (luego, de San Jorge). Tras el derribo anunciado, en los comienzos del siglo XX, el Patio fue vendido a un anticuario parisino, y la câ”œâ•‘pula, desmontada y extraviada. Fuente visual: www.bildindex.de/', 1560, 1560, 1560, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24927586666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24927586666.webp', 'https://www.flickr.com/photos/zaragozaantigua/24927586666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20942, 'San Pedro Apâ”œâ”‚stol 1563', 'Vista parcial de la vista de Zaragoza realizada en 1663 por el dibujante Anton van der Wyngaerde/Antonio de las Viâ”œâ–’as, centrada en la iglesia de San Pedro Apâ”œâ”‚stol, que aparece destacada. En torno a ella figuran a la izquierda las iglesias de San Juan el Viejo y San Andrâ”œآ®s Apâ”œâ”‚stol, a la derecha la iglesia de San Gil Abad, y por encima la iglesia del convento de San Francisco. Se ubicaba en la esquina entre las calles Alta y Baja de San Pedro, actual calle de Don Jaime I.', 1563, 1563, 1563, 'Siglo XIX', 'CENTRO', 41.65324400, -0.87830800, '0101000020E6100000DB15FA60191BECBF7427D87F9DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387421958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387421958.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387421958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24044, 'Plaza de Salamero 1985', 'Imagen capturada en la plaza de Salamero (antigua de Santa Fe), durante la Huelga General del 20 de junio de ese aâ”œâ–’o, convocada por el sindicato Comisiones Obreras (con Marcelino Camacho Abad como Secretario General), y sindicatos con menos afiliaciâ”œâ”‚n, como CNT y USO, como muestra de rechazo a la reforma de las pensiones prevista por el ejecutivo socialista encabezado por Felipe Gonzâ”œأ­lez Mâ”œأ­rquez. Todavâ”œآ،a no se habâ”œآ،a inventado el concepto "huelga polâ”œآ،tica", y esta se quedâ”œâ”‚ sâ”œâ”‚lo en "huelga econâ”œâ”‚mica", como protesta por la primera de las sucesivas reformas a la baja del sistema pâ”œâ•‘blico de pensiones. Ni UGT, ni otras centrales sindicales de orientaciâ”œâ”‚n varia secundaron la huelga, que fue considerada un "fracaso", pues el Gobierno sacâ”œâ”‚ adelante la reforma sin demasiados agobios populares, o parlamentarios. En el editorial del dâ”œآ،a despuâ”œآ®s a esta huelga, el director del Diario 16, Pedro J. Ramâ”œآ،rez, se refiriâ”œâ”‚ a los convocantes en estos tâ”œآ®rminos: "Algunos comunistas son capaces de pasarse por el arco del triunfo todas las reglas de la democracia y sustituirlas por las de una implacable, fetichista, ensotanada y curil inquisiciâ”œâ”‚n (..) este es, irresponsable, frâ”œآ،volo, anticuado, Marcelino Camacho." En la imagen, pancarta de la Federaciâ”œâ”‚n del Metal de CCOO Aragâ”œâ”‚n (que incluye el coloquial palabro "Gâ”œâ•‌elga", en lugar de Huelga), y canto de la Internacional (comunista). Al fondo, las fachadas de algunos de los edificios impares de la antigua calle de la Biblioteca, ya integrados en el entorno de la nueva plaza de Salamero tras el derribo de los antiguos nâ”œâ•‘meros pares, aunque su futuro estaba cantado: los nâ”œâ•‘meros 9, 11 y 13 ya habâ”œآ،an sido derribados, y los nâ”œâ•‘meros 3, 5 y 7 estaban en trâ”œأ­nsito hacia el mismo final. En el gran solar resultante serâ”œآ،a construido poco despuâ”œآ®s el gran bloque moderno del nâ”¬â•‘ 30 de la avenida de Câ”œآ®sar Augusto, de nombre "Verdi". Sâ”œâ”‚lo perdura el esquinero edificio del actual nâ”¬â•‘ 50 de la calle de Azoque. A la derecha, el chaflanero nuevo bloque recayente a l', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65223400, -0.88408700, '0101000020E61000003733FAD1704AECBF6DAB59677CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30938338851.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30938338851.webp', 'https://www.flickr.com/photos/zaragozaantigua/30938338851/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20963, 'Coso Medio 1853', 'Perspectiva de la casa del Excmo. Sr. Conde de Aranda a la calle del Coso de Zaragoza. Estado en que quedâ”œâ”‚ despuâ”œآ®s de los Sitios. Tinta y acuarela. Eusebio Blasco y Taula, 1853. Archivo Municipal de Zaragoza. Segâ”œâ•‘n se ve, â”œآ®ste fue el domicilio del Conde de Aranda (1718-1798) en Zaragoza. Y parece ser que su estado semiesquelâ”œآ®tico se debe a la acciâ”œâ”‚n de las batallas de los Sitios (1808-1809). La esquina con la calle Santa Catalina que reproduce el curioso dibujo corresponde con el actual nâ”œâ•‘mero 84 del Coso Medio, y llega hasta el 86. El edificio original, de 1512, fue palacio de Miguel Velâ”œأ­zquez Climent. Algunos de sus restos reposan en el interior del hotel que hoy ocupa el nâ”œâ•‘mero 86 de esa calle zaragozana: www.flickr.com/photos/zaragozaantigua/15768063741/', 1853, 1853, 1853, 'Siglo XIX', 'CENTRO', 41.65119800, -0.87836000, '0101000020E61000007AAA436E861BECBF3D9CC0745AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661782775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661782775.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661782775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21027, 'Casa de Zaporta 1868', 'Foto: Robert Peters Napper "Patio de la casa de Zaporta o de la Infanta", imagen nâ”¬â•‘ 54 para la ediciâ”œâ”‚n de Francis Frith & Co. (1863-1870) del â”œأ­lbum "Spanish Photographs". Desde la galerâ”œآ،a este, se ha capturado el lado oeste, el de las escaleras de acceso desde el patio inferior. Cubriendo esas escaleras se encontraba una singular y perdida câ”œâ•‘pula. tallada en madera y formas mudâ”œآ®jares. Fuente: Fototeca del Patrimonio Histâ”œâ”‚rico (www.mcu.es/)', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22566288301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22566288301.webp', 'https://www.flickr.com/photos/zaragozaantigua/22566288301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21038, 'Insurreciâ”œâ”‚n republicana 1869', 'Dibujo titulado "Una calle de Zaragoza despuâ”œآ®s del combate", como ilustraciâ”œâ”‚n de los breves e intensos combates habidos tras la insurrecciâ”œâ”‚n republicana federal iniciada el 6 de octubre de ese aâ”œâ–’o en la ciudad, duramente contestada un par de dâ”œآ،as despuâ”œآ®s por las tropas regulares del gobierno provisional (1869-71) del Sexenio Democrâ”œأ­tico (1868-1874), con Prim como presidente, y Serrano como regente. La genâ”œآ®rica localizaciâ”œâ”‚n del dibujo presenta como referencia urbana, al fondo, la Torre Nueva, cuya inclinaciâ”œâ”‚n hacia el SW ubicarâ”œآ،a la imagen, aproximadamente, en el entorno de la calle de Don Jaime I con el cruce de la calle Torre Nueva. Fuente visual: revista El Museo Universal (Madrid, 31/10/1869).', 1869, 1869, 1869, 'Siglo XIX', 'CENTRO', 41.65334800, -0.87855100, '0101000020E610000071C79BFC161DECBF197442E8A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36443956765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36443956765.webp', 'https://www.flickr.com/photos/zaragozaantigua/36443956765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21043, 'Coso Medio 1860', 'Imagen realizada durante la estancia en Zaragoza de la reina Isabel II en octubre de ese aâ”œâ–’o. La escena reproduce el efâ”œآ،mero "obelisco" o torreâ”œâ”‚n "de gusto â”œأ­rabe", dedicado a SS.MM. y decorado con alegorâ”œآ،as relacionadas con la agricultura, la industria y el comercio, temporalmente ubicado en el tramo medio del Coso, que aparece profusamente decorado a base de maderos clavados en el terroso suelo y resaltados con bandas bicolores. A la izquierda, manzanas entre la plaza de la Constituciâ”œâ”‚n, al fondo, en cuya esquina destaca la gran fachada recayente al Coso de la Fonda de Europa de Gaudencio Zoppetti, la calle de la Soledad, luego de los Sitios, y la reciente calle de Blancas, originalmente trazada para llegar hasta cerca del antiguo monasterio de Santa Engracia, si bien se detendrâ”œآ،a en el cruce con la calle de San Miguel. A la derecha, tramo entre las calles del Refugio, luego del Teatro, de San Cristâ”œâ”‚bal del Coso, luego del Romero, y de la Subida de la Verâ”œâ”‚nica, luego de San Pedro Nolasco, donde se destaca tal vez la â”œâ•‘nica fotografâ”œآ،a donde aparece la fachada de la antigua casa de Baltasar Pâ”œآ®rez de Nueros. podo despuâ”œآ®s derribada y donde se erigirâ”œآ،a la casa del marquâ”œآ®s de Fuente Olivar', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65140000, -0.87895800, '0101000020E610000099D711876C20ECBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46459247052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46459247052.webp', 'https://www.flickr.com/photos/zaragozaantigua/46459247052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21109, 'Casa de Zaporta 1889', '"Saragosse. La maison de l''Infante. La cour". En el patio de la antigua casa de Gabriel Zaporta, realquilado a particulares, acoge en esta imagen el taller de carpinterâ”œآ،a de Ezequiel Gonzâ”œأ­lez y el taller de ebanisterâ”œآ،a de Hipâ”œâ”‚lito Loscos. En la primera planta estaba la fâ”œأ­brica de pianos de pared de Pâ”œآ،o Perales.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22551642760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22551642760.webp', 'https://www.flickr.com/photos/zaragozaantigua/22551642760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21114, 'Casa de Zaporta 1889', '"Zaragoza, Casa de los Infantes (Casa Zaporta)". El â”œâ•‘ltimo tercio del siglo XIX fue muy movido para el antiguo Palacio de Zaporta, de la calle de San Jorge, antigua Alta de San Pedro. Tras un incendio en 1864, fue restaurado y multiarrendado a diversas actividades industriosas. En una de las dependencias de la primera planta se ubicâ”œâ”‚ la "Fâ”œأ­brica de Pianos de Pâ”œآ،o Perales", de donde salâ”œآ،an notables pianos de pared, y en la planta baja se montaron talleres de carpinterâ”œآ،a y ebanisterâ”œآ،a. Con tanta madera, saltâ”œâ”‚ la chispa, y a poco de finalizar el siglo un nuevo incendio dejâ”œâ”‚ al Palacio en muy malas condiciones. De ahâ”œآ،, al derribo, fue todo un natural. Dicen. En la imagen, captura fotogrâ”œأ­fica previa a ese â”œâ•‘ltimo incendio, con vista parcial del lado oeste del palaciego patio, que daba acceso a las escaleras de subida al primer piso, donde unos tabiques delimitan la "Fâ”œأ­brica de Pianos de Pâ”œآ،o Perales". Tal vez el seâ”œâ–’or que se asoma, curioso, fuera el propio Pâ”œآ،o. Tras el incendio, se mudarâ”œآ،a a la cercana calle de Don Jaime I.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65280900, -0.87784400, '0101000020E6100000A3ACDF4C4C17ECBF69C4CC3E8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24650941310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24650941310.webp', 'https://www.flickr.com/photos/zaragozaantigua/24650941310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21136, 'Casa de Zaporta 1894', 'A.M.Z. Sign. 0859. Patio de la Infanta procedente de la desaparecida Casa de Zaporta, Zaragoza. [1894] Reproducciâ”œâ”‚n de fotografâ”œآ،a de Laurent del patio de la Infanta, perteneciente a la casa de Zaporta, sita en la calle San Jorge (actual Monte de Piedad). Las piedras se pueden ver, remontadas hoy, dentro del rascacielos de la sede central del banco Ibercaja, en la plaza de Basilio Paraâ”œآ،so.', 1894, 1894, 1894, 'Siglo XIX', 'CENTRO', 41.65270200, -0.87771000, '0101000020E6100000BCE82B483316ECBF530438BD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672230010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672230010.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672230010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21144, 'Casa de Zaporta c.1890', 'Colecciâ”œâ”‚n Antonio Arguas, finales del XIX. Portada completa, con ventana superior, del palacio de Zaporta. En su interior, el patio de la Infanta. El edificio se derribâ”œâ”‚ en 1903.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65266300, -0.87754700, '0101000020E6100000417E3672DD14ECBF952710768AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14984883827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14984883827.webp', 'https://www.flickr.com/photos/zaragozaantigua/14984883827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21171, 'Casa de Zaporta 1893', 'Acuarela de Andrew N. Prentice, copia del â”œâ”‚leo "Celebrada Casa de la Infanta de Zaragoza. La salida del combate", pintado por Pablo Gonzalvo en 1868 y en paradero desconocido. Fuente: Caja de Ahorros de Zaragoza, 1951.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.65274200, -0.87765300, '0101000020E6100000AC8F87BEBB15ECBFE25CC30C8DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29677097665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29677097665.webp', 'https://www.flickr.com/photos/zaragozaantigua/29677097665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
